mapper.select:
SELECT ID, QUIZ_ATTEMPT_CREATE_AT, QUIZ_ATTEMPT_SCORE, QUIZ_ATTEMPT_TOTAL_COUNT, USER_ID, QUIZ_ID
FROM TBL_QUIZ_ATTEMPT
WHERE ID = #{id}

mapper.update:
UPDATE TBL_QUIZ_ATTEMPT
SET QUIZ_ATTEMPT_SCORE = #{quizAttemptScore},
    QUIZ_ATTEMPT_TOTAL_COUNT = #{quizAttemptTotalCount}
WHERE ID = #{id}
